import { NgClass } from '@angular/common';
import { Component, computed, input } from '@angular/core';
import { RouterLink } from '@angular/router';
import {
  MinimizedApiMemberSummary,
  ParsedCanonicalReference,
} from '@ngrx-io/shared';

@Component({
  selector: 'ngrx-symbol-chip',
  template: `
    <a [routerLink]="url()">
      <span [ngClass]="kind()">{{ firstLetterOfKind() }}</span>
      {{ symbol().name }}
    </a>
  `,
  styles: [
    `
      a {
        font-family: 'Oxanium', sans-serif;
        display: flex;
        align-items: center;
        text-decoration: none;
        cursor: pointer;
        color: var(--ngrx-text-secondary);
        transition: color 0.2s;
      }

      a:hover {
        color: var(--ngrx-accent);
      }

      span {
        display: inline-block;
        width: 1.5em;
        text-align: center;
        margin: 0 0.5em 0 0;
        border-radius: 2px;
        font-weight: bold;
        font-size: 12px;
      }

      .EntryPoint {
        background-color: #f8d7da;
        color: #721c24;
      }

      .Function {
        background-color: #d4edda;
        color: #155724;
      }

      .Class {
        background-color: #cce5ff;
        color: #004085;
      }

      .TypeAlias {
        background-color: #fff3cd;
        color: #856404;
      }

      .Interface {
        background-color: #d1ecf1;
        color: #0c5460;
      }

      .Enum {
        background-color: #f8d7da;
        color: #721c24;
      }

      .Variable {
        background-color: #f8d7da;
        color: #721c24;
      }

      .Property {
        background-color: #f8d7da;
        color: #721c24;
      }

      .Method {
        background-color: #d4edda;
        color: #155724;
      }
    `,
  ],
  imports: [RouterLink, NgClass],
})
export class SymbolChipComponent {
  symbol = input.required<MinimizedApiMemberSummary>();
  kind = computed(() => this.symbol().kind);
  firstLetterOfKind = computed(() => this.kind().charAt(0).toUpperCase());
  parsedReference = computed(
    () => new ParsedCanonicalReference(this.symbol().canonicalReference)
  );
  url = computed(() => {
    const [_ngrx, ...rest] = this.parsedReference().package.split('/');
    return `/api/${rest.join('/')}/${this.parsedReference().name}`;
  });
}

import { Component, Input } from '@angular/core';

import { Book } from '@example-app/books/models';

@Component({
  selector: 'bc-book-preview',
  template: `
    <a [routerLink]="['/books', id]">
      <mat-card>
        <mat-card-title-group>
          <img
            mat-card-sm-image
            *ngIf="thumbnail"
            [src]="thumbnail"
            [alt]="title"
          />
          <mat-card-title>{{ title | bcEllipsis: 35 }}</mat-card-title>
          <mat-card-subtitle *ngIf="subtitle">{{
            subtitle | bcEllipsis: 40
          }}</mat-card-subtitle>
        </mat-card-title-group>
        <mat-card-content>
          <p *ngIf="description">{{ description | bcEllipsis }}</p>
        </mat-card-content>
        <mat-card-footer>
          <bc-book-authors [book]="book"></bc-book-authors>
        </mat-card-footer>
      </mat-card>
    </a>
  `,
  styles: [
    `
      :host,
      a {
        display: flex;
      }

      mat-card {
        width: 400px;
        margin: 1rem;
        padding: 1rem;
        display: flex;
        flex-direction: column;
        justify-content: space-between;
      }

      @media only screen and (max-width: 768px) {
        mat-card {
          margin: 1rem 0 !important;
        }
      }

      mat-card:hover {
        box-shadow: 3px 3px 16px -2px rgba(0, 0, 0, 0.5);
      }

      a {
        color: inherit;
        text-decoration: none;
      }

      img {
        width: 60px;
        min-width: 60px;
        margin-left: 5px;
      }

      span {
        display: inline-block;
        font-size: 13px;
      }

      mat-card-content {
        padding: 0;
        margin: 1rem 0;
      }
    `,
  ],
  standalone: false,
})
export class BookPreviewComponent {
  @Input() book!: Book;

  get id() {
    return this.book.id;
  }

  get title() {
    return this.book.volumeInfo.title;
  }

  get subtitle() {
    return this.book.volumeInfo.subtitle;
  }

  get description() {
    return this.book.volumeInfo.description;
  }

  get thumbnail(): string | boolean {
    if (this.book.volumeInfo.imageLinks) {
      return this.book.volumeInfo.imageLinks.smallThumbnail.replace(
        'http:',
        ''
      );
    }

    return false;
  }
}

import { createESLintRule } from '../utils/create-eslint-rule';
import { AST_NODE_TYPES, TSESTree } from '@typescript-eslint/utils';

export type Options = [];
export type MessageIds = 'computedMissingReturn';
export const RULE_NAME = 'computed-must-return';

export default createESLintRule<[], MessageIds>({
  name: RULE_NAME,
  meta: {
    type: 'problem',
    docs: {
      description: `Ensures that computed() returns a value. Omitting the value is likely a mistake.`,
    },
    schema: [],
    messages: {
      computedMissingReturn: 'computed() is missing a return value',
    },
  },
  defaultOptions: [],
  create(context) {
    const functionStack: {
      node: TSESTree.FunctionExpression | TSESTree.ArrowFunctionExpression;
      hasReturn: boolean;
    }[] = [];

    function enterFunction(
      node: TSESTree.FunctionExpression | TSESTree.ArrowFunctionExpression,
    ) {
      functionStack.push({
        node,
        hasReturn: false,
      });
    }

    function exitFunction(
      node: TSESTree.FunctionExpression | TSESTree.ArrowFunctionExpression,
    ) {
      const funcInfo = functionStack.pop();

      if (
        node.parent?.type === AST_NODE_TYPES.CallExpression &&
        node.parent.callee.type === AST_NODE_TYPES.Identifier &&
        node.parent.callee.name === 'computed' &&
        node.parent.arguments[0] === node
      ) {
        // Arrow function without a body
        if (
          node.type === AST_NODE_TYPES.ArrowFunctionExpression &&
          node.expression
        ) {
          return;
        }

        if (!funcInfo?.hasReturn) {
          context.report({
            node: node.parent,
            messageId: 'computedMissingReturn',
          });
        }
      }
    }

    return {
      ArrowFunctionExpression: enterFunction,
      'ArrowFunctionExpression:exit': exitFunction,
      FunctionExpression: enterFunction,
      'FunctionExpression:exit': exitFunction,

      ReturnStatement(node: TSESTree.ReturnStatement) {
        if (node.argument && functionStack.length > 0) {
          functionStack[functionStack.length - 1].hasReturn = true;
        }
      },
    };
  },
});

export const RULE_DOCS_EXTENSION = {
  rationale:
    "`computed()` is used to transform signal values. If no value is returned from `computed()`, it's likely a mistake.",
};

